head.script:
//==================================================================================================================
// id       : op_203_01_04b 
// 이름     : 사유화차배정량수정
// 경로     : 물류/작업계획/철송/
// 작 성 자 : 조성빈
// 작 업 일 : 2025-12-23
// 사용계정 : 내부
// 비고     : 
// 레포트   :
// 업로드   :
// 다운로드 : 
// 호출     :
//            op_203_01_04p(저감액 우선순위 현황) - 저감액 우선순위 버튼 클릭
//==================================================================================================================
scwin.toDay;
scwin.dateStr;
scwin.CREATE_AUTH;

scwin.onpageload = function() {
    scwin.toDay = $c.date.getServerDateTime("yyyyMMdd");
    scwin.dateStr = scwin.toDay;
    scwin.CREATE_AUTH = $p.getFrame().CREATE_AUTH;
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {

        ica_signDt.setValue(scwin.dateStr);
        ica_signDt.focus();

        // $c.gus.cfDisableBtn([btn_save]);

        // $p.setTimeout(function() {
        //     ica_signDt.setValue("20061227")
        // }, {"delay":50});

    }, {"delay":50});
};

//-------------------------------------------------------------------------
// 사유화차배정량수정 조회
//-------------------------------------------------------------------------
scwin.f_qeryList = async function (){
    var valid = await $c.gus.cfValidate([ica_signDt])
  	if (!valid) {	// 신청일자, 출발역
  		return;
	}
    ds_QueryCondition.set("reqDt", ica_signDt.getValue());                      // 신청일자
    ds_QueryCondition.set("dptStn", ed_begintrainWorkPlaceCd.getValue());       // 출발역
    ds_QueryCondition.set("arvStn", ed_endtrainWorkPlaceCd.getValue());         // 도착역

	$c.sbm.execute(sbm_RetrievePrivatetrainAssign);
}; 

//-------------------------------------------------------------------------
// 저장버튼 처리 
//-------------------------------------------------------------------------
scwin.f_Save = async function (eqCd){
   var teuB_under = 0;
   var realTeuA = 0;

    for(var i = 0; i < ds_PrivatetrainAssign.getRowCount(); i++){
        if (ds_PrivatetrainAssign.getCellData(i, "clsCd") == "02"){
            teuB_under += parseInt(ds_PrivatetrainAssign.getCellData(i, "teu"));
            if (scwin.CREATE_AUTH != "C") {
          	    //생성권한이 없는 사람은 배정작업이 끝난 후에는 수정을 할 수 없다
                if ( ds_PrivatetrainAssign.getCellData(i,"cnt20Empty") > 0
                    || ds_PrivatetrainAssign.getCellData(i,"cnt20Full") > 0
                    || ds_PrivatetrainAssign.getCellData(i,"cnt40Empty") > 0
                    || ds_PrivatetrainAssign.getCellData(i,"cnt40Full") > 0
                    || ds_PrivatetrainAssign.getCellData(i,"cnt45Empty") > 0
                    || ds_PrivatetrainAssign.getCellData(i,"cnt45Full") > 0 ) {
                    await $c.gus.cfAlertMsg("이미 배정작업이 끝났습니다");
                    return;
                }
	        }
        }
        if(ds_PrivatetrainAssign.getCellData(i, "clsCd") == "05"){
            realTeuA += parseInt(ds_PrivatetrainAssign.getCellData(i, "teu"));
        }
    }
    if(parseInt(teuB_under) > 202){
        await $c.gus.cfAlertMsg("배정량이 202 TEU 초과했습니다.");
        return;
    }
    var conf = await $c.win.confirm(MSG_CM_CRM_001) 
    if (conf){  
        $c.sbm.execute(sbm_UpdatePrivatetrainAssign);
    }
};

//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
	$c.gus.cfInitObjects(tbl_search, null);
	ica_signDt.focus();
	ica_signDt.setValue(scwin.dateStr);
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {

  	// 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  	if (!await $c.gus.cfCanOpenPopup(inObj, pairObj)) return;

	// 짝이 되는 오브젝트의 값 제거
	$c.gus.cfClearPairObj(pairObj);

	// 검색어 세팅
	var pVal = $c.gus.cfGetValue(inObj);

	// inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
	    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
	else
	    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
  	// 선언부
	switch (disGubun)
  	{
  		case 1:   // 출발역 역명 팝업	
            udc_begintrainWorkPlace.setSelectId("retrieveTrainWorkPlace");
  			udc_begintrainWorkPlace.cfCommonPopUp(scwin.udc_begintrainWorkPlace_callBackFunc	// XML상의 SELECT ID	
                                                 ,pCode					                        // 화면에서의 ??? Code Element의	Value
                                                 ,pName					                        // 화면에서의 ??? Name Element의	Value
                                                 ,pClose				                        // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                                 ,null					                        // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                                 ,null					                        // Title순서	
                                                 ,null					                        // 보여주는 각 컬럼들의 폭	
                                                 ,null					                        // 컬럼중에서 숨기는	컬럼 지정	
                                                 ,null					                        // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                                 ,null					                        // POP-UP뛰을때 원도우의	사용자 정의	폭
                                                 ,null					                        // POP-UP뛰을때 우도우의	사용자 정의	높이	
                                                 ,null					                        // 윈도우 위치 Y좌표	
                                                 ,null					                        // 윈도우 위치 X좌표
                                                 ,null					                        // 중복체크여부	("F")
                                                 ,pAllSearch					                // 전체검색허용여부	("F")
                                                 ,"역명조회,작업장코드,작업장명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            ); 
			break;
  		case 2:  // 도착역 역명 팝업	
            udc_endtrainWorkPlace.setSelectId("retrieveTrainWorkPlace");
  			udc_endtrainWorkPlace.cfCommonPopUp(scwin.udc_endtrainWorkPlace_callBackFunc	// XML상의 SELECT ID	
  									           ,pCode					                    // 화면에서의 ??? Code Element의	Value
  									           ,pName					                    // 화면에서의 ??? Name Element의	Value
  									           ,pClose					                    // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
  									           ,null					                    // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
  									           ,null					                    // Title순서	
  									           ,null					                    // 보여주는 각 컬럼들의 폭	
  									           ,null					                    // 컬럼중에서 숨기는	컬럼 지정	
  									           ,null					                    // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
  									           ,null					                    // POP-UP뛰을때 원도우의	사용자 정의	폭
  									           ,null					                    // POP-UP뛰을때 우도우의	사용자 정의	높이	
  									           ,null					                    // 윈도우 위치 Y좌표	
  									           ,null					                    // 윈도우 위치 X좌표
  									           ,null					                    // 중복체크여부	("F")
  									           ,pAllSearch					                // 전체검색허용여부	("F")
  									           ,"역명조회,작업장코드,작업장명"				 // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            ); 
			break;
    }	
};

//-------------------------------------------------------------------------
// 계산 처리 **
//-------------------------------------------------------------------------
scwin.f_internalCal = function(row, colid, oldData, newData) {  
    if(colid == "cnt20Empty" || colid == "cnt20Full" || colid == "cnt40Empty" 
        || colid == "cnt40Full"  || colid == "cnt45Empty" || colid == "cnt45Full") {

        var cnt20Empty  = parseInt(ds_PrivatetrainAssign.getCellData(row, "cnt20Empty"));
        var cnt20Full   = parseInt(ds_PrivatetrainAssign.getCellData(row, "cnt20Full"));
        var cnt40Empty  = parseInt(ds_PrivatetrainAssign.getCellData(row, "cnt40Empty"));
        var cnt40Full   = parseInt(ds_PrivatetrainAssign.getCellData(row, "cnt40Full"));
        var cnt45Empty  = parseInt(ds_PrivatetrainAssign.getCellData(row, "cnt45Empty"));
        var cnt45Full   = parseInt(ds_PrivatetrainAssign.getCellData(row, "cnt45Full"));
        if (colid == "cnt20Empty") cnt20Empty = parseInt(newData);
        if (colid == "cnt20Full") cnt20Full = parseInt(newData);
        if (colid == "cnt40Empty") cnt40Empty = parseInt(newData);
        if (colid == "cnt40Full") cnt40Full = parseInt(newData);
        if (colid == "cnt45Empty") cnt45Empty = parseInt(newData);
        if (colid == "cnt45Full") cnt45Full = parseInt(newData);

        if(ds_PrivatetrainAssign.getCellData(row, colid) == "") {
            ds_PrivatetrainAssign.setCellData(row, colid, 0);
        }
        ds_PrivatetrainAssign.setCellData(row, "sumTeu", cnt20Empty
                                                       + cnt20Full
                                                       + cnt40Empty
                                                       + cnt40Full
                                                       + cnt45Empty
                                                       + cnt45Full
        );
        ds_PrivatetrainAssign.setCellData(row, "teu", cnt20Empty
                                                    + cnt20Full
                                                    + (  cnt40Empty
                                                       + cnt40Full
                                                       + cnt45Empty
                                                       + cnt45Full
                                                    ) * 2
        );
        if (ds_PrivatetrainAssign.getCellData(row, "clsCd") == "02") {    
            scwin.f_internalCal2(row, colid, oldData);
        }                                        
    }
    scwin.f_totalUnderValue();
};

//-------------------------------------------------------------------------
// 그리드 아래쪽 합계 계산 처리 **
//-------------------------------------------------------------------------
scwin.f_totalUnderValue = function (){    
    var total_cnt    = ds_PrivatetrainAssign.getRowCount();
    var teuA_under   = 0;
    var teuB_under   = 0;
    var teuC_under   = 0;
    var realTeuA     = 0;
    var realTeuB     = 0;
    var realTeuC     = 0;
    var div_str      = "";
    for(var i = 0; i < total_cnt; i++){
        var color = ds_PrivatetrainAssign.getCellData(i,'bgColordat');
        gr_PrivatetrainAssign.setCellColor(i, 'dptStnWrkPlNm', color);
        gr_PrivatetrainAssign.setCellColor(i, 'arvStnWrkPlNm', color);
        gr_PrivatetrainAssign.setCellColor(i, 'clsNm', color);
        gr_PrivatetrainAssign.setCellColor(i, 'cnt20Empty', color);
        gr_PrivatetrainAssign.setCellColor(i, 'cnt20Full', color);
        gr_PrivatetrainAssign.setCellColor(i, 'cnt40Empty', color);
        gr_PrivatetrainAssign.setCellColor(i, 'cnt40Full', color);
        gr_PrivatetrainAssign.setCellColor(i, 'cnt45Empty', color);
        gr_PrivatetrainAssign.setCellColor(i, 'cnt45Full', color);
        gr_PrivatetrainAssign.setCellColor(i, 'teu', color);
        if (color == "Red"){
            gr_PrivatetrainAssign.setCellColor(i, 'reference', "RED");
        }
        if (ds_PrivatetrainAssign.getCellData(i, "reference") == 0){
            // ds_PrivatetrainAssign.setCellData(i, "reference", "");
        }

        if(ds_PrivatetrainAssign.getCellData(i, "clsCd") == "01"){
            teuA_under += parseInt(ds_PrivatetrainAssign.getCellData(i, "teu"));
        }
        if(ds_PrivatetrainAssign.getCellData(i,"clsCd") == "02"){
            teuB_under += parseInt(ds_PrivatetrainAssign.getCellData(i, "teu"));
        }
        if(ds_PrivatetrainAssign.getCellData(i,"clsCd") == "03"){
            teuC_under += parseInt(ds_PrivatetrainAssign.getCellData(i, "teu"));
        }
        if(ds_PrivatetrainAssign.getCellData(i, "clsCd") == "04"){
            realTeuA += parseInt(ds_PrivatetrainAssign.getCellData(i, "teu"));
        }
        if(ds_PrivatetrainAssign.getCellData(i,"clsCd") == "05"){
            realTeuB += parseInt(ds_PrivatetrainAssign.getCellData(i, "teu"));
        }
        if(ds_PrivatetrainAssign.getCellData(i,"clsCd") == "06"){
            realTeuC += parseInt(ds_PrivatetrainAssign.getCellData(i, "teu"));
        }
    }
    //그리드 하단 SUM에 색상 지정 
    gr_PrivatetrainAssign.setFooterStyle('footer_dptStnWrkPlNm', 'color', "Black");
    gr_PrivatetrainAssign.setFooterStyle('footer_arvStnWrkPlNm', 'color', "Black");   
    gr_PrivatetrainAssign.setFooterStyle('footer_clsNm', 'color', "Red");
    gr_PrivatetrainAssign.setFooterStyle('footer_cnt20Empty', 'color', "Red");
    gr_PrivatetrainAssign.setFooterStyle('footer_cnt20Full', 'color', "Blue"); 
    gr_PrivatetrainAssign.setFooterStyle('footer_cnt40Empty', 'color', "Blue");
    gr_PrivatetrainAssign.setFooterStyle('footer_cnt40Full', 'color', "Red");
    gr_PrivatetrainAssign.setFooterStyle('footer_cnt45Empty', 'color', "Red");   
    gr_PrivatetrainAssign.setFooterStyle('footer_cnt45Full', 'color', "Blue");
    gr_PrivatetrainAssign.setFooterStyle('footer_sumTeu', 'color', "Blue");
    gr_PrivatetrainAssign.setFooterStyle('footer_teu', 'color', "Black");   
    gr_PrivatetrainAssign.setFooterStyle('footer_reference', 'color', "Black");

    gr_PrivatetrainAssign.setFooterValue('footer_arvStnWrkPlNm', teuA_under + " TEU");
    gr_PrivatetrainAssign.setFooterValue('footer_cnt20Empty', teuB_under + " TEU");
    gr_PrivatetrainAssign.setFooterValue('footer_cnt40Empty', teuC_under + " TEU");
    gr_PrivatetrainAssign.setFooterValue('footer_cnt45Empty', parseInt(realTeuA) + " TEU");
    gr_PrivatetrainAssign.setFooterValue('footer_sumTeu', parseInt(realTeuB) + " TEU");
    gr_PrivatetrainAssign.setFooterValue('footer_reference', parseInt(realTeuC) + " TEU");
};

