//-------------------------------------------------------------------------
// 사유화차 배치실행
//-------------------------------------------------------------------------
scwin.f_Batch = async function (){
    //  ExecutePrivatetrainAssignCMD
    var conf = await $c.win.confirmMsg("사유화차 배정 배치를 실행하시겠습니까?");
	if (conf) {  
        $c.sbm.execute(sbm_batch);
    }
};

scwin.f_runExcel = async function(varGrNm) {
    var totCnt      = ds_hidden.get("grPrivatetrainAssignTotCnt");
    var sheetTitle  = '사유화차배정량수정';
    if( totCnt != "0"){
        var cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
        if (cfrm){
            // cfGridToExcel(varGrNm, sheetTitle, sheetTitle, 2+4+8+16);	
            const infoArr = [ ];
            const options = {
                fileName : "사유화차배정량수정.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
                sheetName: "사유화차배정량수정",
                // startRowIndex: 2,
                type : "1",
                // removeColumns: "0,21",
                hiddenVisible : true,
                oddRowBackgroundColor  : "",                        // excel파일에서 그리드 body의 홀수줄의 배경색
                evenRowBackgroundColor : "#F5FFF5"                  // excel파일에서 그리드 body의 짝수줄의 배경색
            };
            $c.data.downloadGridViewExcel(gr_PrivatetrainAssign, options, infoArr);
        }
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);    
    }
};

scwin.f_internalCal2 = async function(row, colid, oldData) {
    if(    colid == "cnt20Empty" || colid == "cnt20Full" 
        || colid == "cnt40Empty" || colid == "cnt40Full" 
        || colid == "cnt45Empty" || colid == "cnt45Full") {

		if( ds_PrivatetrainAssign.getCellData(row, "dayCapaTeu") != 0 
	      	&& (ds_PrivatetrainAssign.getCellData(row, "teu") > ds_PrivatetrainAssign.getCellData(row, "dayCapaTeu")) ) {
				await $c.gus.cfAlertMsg("당일 최대 전용화차 신청량이 초과되었습니다.");
				ds_PrivatetrainAssign.setCellData(row, colid, oldData); 
				return;
		} 	  
	}
	var rowCount = ds_PrivatetrainAssign.getRowCount();
	var sumTeu = 0;

	for(var i = 0 ; i < rowCount ; i++) {
		if (ds_PrivatetrainAssign.getCellData(i, "clsCd") == "02") {
			if ((ds_PrivatetrainAssign.getCellData(row, "dptStnWrkPlCd") == ds_PrivatetrainAssign.getCellData(i, "dptStnWrkPlCd"))
					&& (ds_PrivatetrainAssign.getCellData(row, "arvStnWrkPlCd") == ds_PrivatetrainAssign.getCellData(i, "arvStnWrkPlCd"))) {
				sumTeu = parseInt(sumTeu) + parseInt(ds_PrivatetrainAssign.getCellData(i, "teu"));
			}
			if (ds_PrivatetrainAssign.getCellData(row, "dayCapaTeu") != 0 
				&& (parseInt(sumTeu) > parseInt(ds_PrivatetrainAssign.getCellData(row, "dayCapaTeu")))) {
				await $c.gus.cfAlertMsg("당일 최대 전용화차 신청량이 초과되었습니다.");
				ds_PrivatetrainAssign.setCellData(row, colid, oldData); 
				return;
			}
		} 
	}
};

