scwin.sbm_RetrievePrivatetrainAssign_submit = function (e) {

};

scwin.sbm_RetrievePrivatetrainAssign_submitdone = async function (e) {
    var rowCnt = ds_PrivatetrainAssign.getRowCount();
    if( rowCnt == 0 ){
		await $c.gus.cfAlertMsg("[사유화차배정량수정 정보] "+ MSG_CM_ERR_003);
  	}
    $c.gus.cfDisableBtn([]);

    txt_PrivatetrainAssign.setValue(rowCnt);
    var rowCnt2 = ds_btAssign.getRowCount()
    txt_btAssign.setValue(rowCnt2);

    scwin.f_totalUnderValue();
    ds_btAssign
    for(var i = 0; i < rowCnt2; i++){
        var color = ds_btAssign.getCellData(i,'bgColordat');

        gr_btAssign.setCellColor(i, 'clsNm', color);
        gr_btAssign.setCellColor(i, 'cnt20Empty', color);
        gr_btAssign.setCellColor(i, 'cnt20Full', color);
        gr_btAssign.setCellColor(i, 'cnt40Empty', color);
        gr_btAssign.setCellColor(i, 'cnt40Full', color);
        gr_btAssign.setCellColor(i, 'cnt45Empty', color);
        gr_btAssign.setCellColor(i, 'cnt45Full', color);
        gr_btAssign.setCellColor(i, 'sumTeu', color);
        gr_btAssign.setCellColor(i, 'teu', color);
    };

    ds_hidden.set("grPrivatetrainAssignTotCnt", rowCnt);
};

