scwin.gr_PrivatetrainAssign_oncellclick = function (Row, columnIndex, Colid) {
    if(Colid == "cnt20Empty" || Colid == "cnt20Full" || Colid == "cnt40Empty" || Colid == "cnt40Full" || Colid == "cnt45Empty" || Colid == "cnt45Full"){
		if (ds_PrivatetrainAssign.getCellData(Row, "clsCd") == "02" || ds_PrivatetrainAssign.getCellData(Row, "clsCd") == "03"){    
			gr_PrivatetrainAssign.setCellReadOnly(Row, "cnt20Empty", false);
			gr_PrivatetrainAssign.setCellReadOnly(Row, "cnt40Empty", false);
			gr_PrivatetrainAssign.setCellReadOnly(Row, "cnt45Empty", false);
			gr_PrivatetrainAssign.setCellReadOnly(Row, "cnt20Full", false);
			gr_PrivatetrainAssign.setCellReadOnly(Row, "cnt40Full", false);
			gr_PrivatetrainAssign.setCellReadOnly(Row, "cnt45Full", false);			

			if((ds_PrivatetrainAssign.getCellData(Row, "clsCd") == "02" 
             || ds_PrivatetrainAssign.getCellData(Row, "clsCd") == "03") && Colid == "cnt45Full"){
				gr_PrivatetrainAssign.setCellReadOnly(Row, "cnt20Empty", true);
				gr_PrivatetrainAssign.setCellReadOnly(Row, "cnt40Empty", true);
				gr_PrivatetrainAssign.setCellReadOnly(Row, "cnt45Empty", true);
				gr_PrivatetrainAssign.setCellReadOnly(Row, "cnt20Full", true);
				gr_PrivatetrainAssign.setCellReadOnly(Row, "cnt40Full", true);
			}		 
	    } else {
			gr_PrivatetrainAssign.setCellReadOnly(Row, "cnt20Empty", true);
			gr_PrivatetrainAssign.setCellReadOnly(Row, "cnt40Empty", true);
			gr_PrivatetrainAssign.setCellReadOnly(Row, "cnt45Empty", true);
			gr_PrivatetrainAssign.setCellReadOnly(Row, "cnt20Full", true);
			gr_PrivatetrainAssign.setCellReadOnly(Row, "cnt40Full", true);
			gr_PrivatetrainAssign.setCellReadOnly(Row, "cnt45Full", true);
		}
	}
};

