scwin.gr_PrivatetrainAssign_oneditend = function (row, columnIndex, value) {

    // OnExit(row,colid,olddata)
    var oldData = ds_PrivatetrainAssign.getCellData(row, columnIndex);
    var colid = gr_PrivatetrainAssign.getColumnID(columnIndex);

    scwin.f_internalCal(row, colid, oldData, value);

    if(ds_PrivatetrainAssign.getCellData(row, "clsCd") == "02" && colid == "cnt45Full"){
        gr_PrivatetrainAssign.setCellReadOnly(row, "cnt20Empty",true);
        gr_PrivatetrainAssign.setCellReadOnly(row, "cnt20Empty",true);
        gr_PrivatetrainAssign.setCellReadOnly(row, "cnt40Empty",true);
        gr_PrivatetrainAssign.setCellReadOnly(row, "cnt45Empty",true);
        gr_PrivatetrainAssign.setCellReadOnly(row, "cnt20Full",true);
        gr_PrivatetrainAssign.setCellReadOnly(row, "cnt40Full",true);
        gr_PrivatetrainAssign.setCellReadOnly(row, "cnt45Full",true);
    }	
    if(ds_PrivatetrainAssign.getCellData(row,"clsCd")=="03" && colid == "cnt45Full"){
        gr_PrivatetrainAssign.setCellReadOnly(row, "cnt20Empty", true);
        gr_PrivatetrainAssign.setCellReadOnly(row, "cnt20Empty", true);
        gr_PrivatetrainAssign.setCellReadOnly(row, "cnt40Empty", true);
        gr_PrivatetrainAssign.setCellReadOnly(row, "cnt45Empty", true);
        gr_PrivatetrainAssign.setCellReadOnly(row, "cnt20Full", true);
        gr_PrivatetrainAssign.setCellReadOnly(row, "cnt40Full", true);
        gr_PrivatetrainAssign.setCellReadOnly(row, "cnt45Full", true);
    }		
};

